"use strict";parserFactory.register("empirenovel.com",()=>new EmpirenovelParser);class EmpirenovelParser extends Parser{constructor(){super()}async getChapterUrls(e,r){let t=this.extractPartialChapterList(e),a=this.getUrlsOfTocPages(e);return(await this.getChaptersFromAllTocPages(t,this.extractPartialChapterList,a,r)).reverse()}getUrlsOfTocPages(e){let r=[],t=[...e.querySelectorAll(".pagination a")].map(e=>new URL(e?.href)?.searchParams?.get("page")).filter(e=>null!==e).map(e=>parseInt(e));if(0<t.length){let a=new URL(e.querySelector(".pagination a").href),l=Math.max(...t);for(let e=2;e<=l;++e)a.searchParams.set("page",e),r.push(a.href)}return r}extractPartialChapterList(e){return[...e.querySelectorAll("a.chapter_link")].map(e=>(e.querySelector(".small")?.remove(),{sourceUrl:e.href,title:e.innerText.trim()}))}findContent(e){return e.querySelector("#read-novel")}extractAuthor(e){let r=e.querySelector("div:nth-child(2) > div > span > a");return null===r?super.extractAuthor(e):r.textContent}extractSubject(e){let r=[...e.querySelectorAll("div:nth-child(1) > ul a")],t=new RegExp("^#");return r.map(e=>e.textContent.trim().replace(t,"")).join(", ")}extractTitleImpl(e){return e.querySelector("h1:not(.show_title)")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.cover")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.col-sm.pe-sm-0 > div:nth-child(1)"),...e.querySelectorAll("div.bg_dark.p-3.my-2.rounded-3.show_details.max-sm-250.w-100")]}}